noncompliant:
list[index] = "value 1";
list[index] = "value 2";  // Noncompliant - unconditional overwrite

dictionary.Add(key, "value 1");
dictionary[key] = "value 2"; // Noncompliant - unconditional overwrite

compliant:
// Only set the value once
list[index] = "value 2";

// Or check before overwriting
if (!dictionary.ContainsKey(key))
{
    dictionary[key] = "value 1";
}
else
{
    dictionary[key] = "value 2"; // Conditional replacement
}
